// Declare an event for every privileged state change and emit it in the setter.
event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
event FeeUpdated(uint256 previousFee, uint256 newFee);

function transferOwnership(address newOwner) external onlyOwner {
    require(newOwner != address(0), "zero address");
    address previousOwner = owner;
    owner = newOwner;
    // Emit so off-chain monitors and indexers can react immediately:
    emit OwnershipTransferred(previousOwner, newOwner);
}

function setFee(uint256 newFee) external onlyOwner {
    uint256 previousFee = fee;
    fee = newFee;
    emit FeeUpdated(previousFee, newFee);
}
